import React, { useRef, useEffect } from 'react';

function GifAnimationControlledByScroll({ scrollPercentage, src }) {
  const imageRef = useRef(null);

  useEffect(() => {
    const image = imageRef.current;
    image.style.width = '100%'; // Ajusta el ancho de la imagen al 100% del contenedor
    const frameIndex = Math.floor(scrollPercentage * image.naturalWidth);
    image.style.objectPosition = `-${frameIndex}px 0`; // Ajusta la posición del frame según el scrollPercentage
  }, [scrollPercentage, src]);

  return (
    <div className="GifAnimationControlledByScroll">
      <img ref={imageRef} src={src} alt="Animated Image" />
    </div>
  );
}

export default GifAnimationControlledByScroll;
